import { describe, expect, test } from "bun:test";

import {
  createSpecPack,
  parseJsonOutput,
  runSourceCli,
  writeTextFile,
} from "./test-helpers";

describe("inspect command", () => {
  test("TC-1.1a / TC-1.2a accepts and records a valid two-file tech-design layout", async () => {
    const specPackRoot = await createSpecPack("inspect-two-file");
    const run = await runSourceCli([
      "inspect",
      "--spec-pack-root",
      specPackRoot,
      "--json",
    ]);

    expect(run.exitCode).toBe(0);
    expect(run.stderr).toBe("");

    const envelope = parseJsonOutput<any>(run.stdout);
    expect(envelope.command).toBe("inspect");
    expect(envelope.status).toBe("ok");
    expect(envelope.outcome).toBe("ready");
    expect(envelope.result.techDesignShape).toBe("two-file");
    expect(envelope.result.artifacts.techDesignCompanionPaths).toEqual([]);
  });

  test("TC-1.1b / TC-1.2b accepts and records a valid four-file tech-design layout", async () => {
    const specPackRoot = await createSpecPack("inspect-four-file", {
      companionMode: "four-file",
    });
    const run = await runSourceCli([
      "inspect",
      "--spec-pack-root",
      specPackRoot,
      "--json",
    ]);

    expect(run.exitCode).toBe(0);

    const envelope = parseJsonOutput<any>(run.stdout);
    expect(envelope.status).toBe("ok");
    expect(envelope.outcome).toBe("ready");
    expect(envelope.result.techDesignShape).toBe("four-file");
    expect(envelope.result.artifacts.techDesignCompanionPaths).toEqual([
      `${specPackRoot}/tech-design-cli-runtime.md`,
      `${specPackRoot}/tech-design-skill-process.md`,
    ]);
  });

  test("TC-1.1c rejects stories.md in place of stories/", async () => {
    const specPackRoot = await createSpecPack("inspect-stories-md", {
      includeStoriesDir: false,
      includeStoriesFile: true,
    });
    const run = await runSourceCli([
      "inspect",
      "--spec-pack-root",
      specPackRoot,
      "--json",
    ]);

    expect(run.exitCode).toBe(3);

    const envelope = parseJsonOutput<any>(run.stdout);
    expect(envelope.status).toBe("blocked");
    expect(envelope.outcome).toBe("blocked");
    expect(envelope.errors[0].code).toBe("INVALID_SPEC_PACK");
    expect(envelope.result.blockers).toContain(
      "Expected stories/ directory but found stories.md"
    );
  });

  test("TC-1.1d identifies a missing required artifact explicitly", async () => {
    const specPackRoot = await createSpecPack("inspect-missing-artifact", {
      includeEpic: false,
    });
    const run = await runSourceCli([
      "inspect",
      "--spec-pack-root",
      specPackRoot,
      "--json",
    ]);

    expect(run.exitCode).toBe(3);

    const envelope = parseJsonOutput<any>(run.stdout);
    expect(envelope.status).toBe("blocked");
    expect(envelope.result.blockers).toContain("Missing required artifact: epic.md");
  });

  test("TC-1.4a records both public prompt inserts when present", async () => {
    const specPackRoot = await createSpecPack("inspect-with-inserts", {
      includeImplInsert: true,
      includeVerifierInsert: true,
    });
    const run = await runSourceCli([
      "inspect",
      "--spec-pack-root",
      specPackRoot,
      "--json",
    ]);

    expect(run.exitCode).toBe(0);

    const envelope = parseJsonOutput<any>(run.stdout);
    expect(envelope.result.inserts.customStoryImplPromptInsert).toBe("present");
    expect(envelope.result.inserts.customStoryVerifierPromptInsert).toBe("present");
  });

  test("TC-1.4b continues normally when public prompt inserts are absent", async () => {
    const specPackRoot = await createSpecPack("inspect-without-inserts");
    const run = await runSourceCli([
      "inspect",
      "--spec-pack-root",
      specPackRoot,
      "--json",
    ]);

    expect(run.exitCode).toBe(0);

    const envelope = parseJsonOutput<any>(run.stdout);
    expect(envelope.status).toBe("ok");
    expect(envelope.result.inserts.customStoryImplPromptInsert).toBe("absent");
    expect(envelope.result.inserts.customStoryVerifierPromptInsert).toBe("absent");
  });

  test("blocks invalid tech-design companion layouts instead of accepting them silently", async () => {
    const specPackRoot = await createSpecPack("inspect-invalid-companions");
    await writeTextFile(
      `${specPackRoot}/tech-design-notes.md`,
      "# Invalid Companion\n"
    );

    const run = await runSourceCli([
      "inspect",
      "--spec-pack-root",
      specPackRoot,
      "--json",
    ]);

    expect(run.exitCode).toBe(3);

    const envelope = parseJsonOutput<any>(run.stdout);
    expect(envelope.status).toBe("blocked");
    expect(envelope.result.blockers).toContain(
      "Invalid tech-design companion layout: expected tech-design-cli-runtime.md and tech-design-skill-process.md for the four-file configuration"
    );
  });
});

import { afterAll, beforeAll, describe, expect, test } from "bun:test";
import { mkdir, rm } from "node:fs/promises";
import { join, resolve } from "node:path";

const ROOT = resolve(import.meta.dir, "../..");
const TEST_ROOT_REL = ".test-tmp/claude-impl-build";
const TEST_DIST_REL = `${TEST_ROOT_REL}/dist`;
const TEST_ROOT = join(ROOT, TEST_ROOT_REL);
const DIST = join(ROOT, TEST_DIST_REL);

let buildExitCode = -1;
let buildOutput = "";

beforeAll(async () => {
  await rm(TEST_ROOT, { recursive: true, force: true });

  const proc = Bun.spawn(["bun", "run", "scripts/build.ts"], {
    cwd: ROOT,
    stdout: "pipe",
    stderr: "pipe",
    env: {
      ...process.env,
      DIST_DIR: TEST_DIST_REL,
    },
  });

  const stdout = await new Response(proc.stdout).text();
  const stderr = await new Response(proc.stderr).text();
  buildOutput = stdout + stderr;
  buildExitCode = await proc.exited;
}, 30_000);

afterAll(async () => {
  await rm(TEST_ROOT, { recursive: true, force: true });
});

async function createSmokeSpecPack(): Promise<string> {
  const specPackRoot = join(TEST_ROOT, "spec-pack");
  await mkdir(join(specPackRoot, "stories"), { recursive: true });
  await Bun.write(join(specPackRoot, "epic.md"), "# Epic\n");
  await Bun.write(join(specPackRoot, "tech-design.md"), "# Technical Design\n");
  await Bun.write(join(specPackRoot, "test-plan.md"), "# Test Plan\n");
  await Bun.write(
    join(specPackRoot, "stories", "00-foundation.md"),
    "# Story 0: Foundation\n"
  );
  return specPackRoot;
}

describe("claude-impl build integration", () => {
  test("registers ls-claude-impl in the manifest and build summary", async () => {
    const manifest = (await Bun.file(join(ROOT, "manifest.json")).json()) as {
      skills: Record<string, unknown>;
    };

    expect(manifest.skills["ls-claude-impl"]).toBeDefined();
    expect(buildExitCode).toBe(0);
    expect(buildOutput).toContain("skill: ls-claude-impl");
  });

  test("packages the claude-impl references into the installed skill output", async () => {
    expect(
      await Bun.file(
        join(DIST, "skills", "ls-claude-impl", "references", "claude-impl-reading-journey.md")
      ).exists()
    ).toBe(true);
    expect(
      await Bun.file(
        join(DIST, "skills", "ls-claude-impl", "references", "claude-impl-process-playbook.md")
      ).exists()
    ).toBe(true);
    expect(
      await Bun.file(
        join(DIST, "skills", "ls-claude-impl", "references", "claude-impl-cli-operations.md")
      ).exists()
    ).toBe(true);
    expect(
      await Bun.file(
        join(DIST, "skills", "ls-claude-impl", "references", "claude-impl-prompt-system.md")
      ).exists()
    ).toBe(true);
  });

  test("copies the bundled cli artifact into the packaged skill", async () => {
    const cliExists = await Bun.file(
      join(DIST, "skills", "ls-claude-impl", "bin", "ls-impl-cli.cjs")
    ).exists();

    expect(cliExists).toBe(true);
  });

  test("runs the bundled cli under Node for inspect", async () => {
    const specPackRoot = await createSmokeSpecPack();
    const proc = Bun.spawn(
      [
        "node",
        join(DIST, "skills", "ls-claude-impl", "bin", "ls-impl-cli.cjs"),
        "inspect",
        "--spec-pack-root",
        specPackRoot,
        "--json",
      ],
      {
        cwd: ROOT,
        stdout: "pipe",
        stderr: "pipe",
      }
    );
    const stdout = await new Response(proc.stdout).text();
    const stderr = await new Response(proc.stderr).text();
    const exitCode = await proc.exited;

    expect(exitCode).toBe(0);
    expect(stderr).toBe("");
    expect(JSON.parse(stdout).outcome).toBe("ready");
  });
});

import { describe, expect, test } from "bun:test";

import { createSpecPack, parseJsonOutput, runSourceCli } from "./test-helpers";

describe("cli io contract", () => {
  test("--json emits exactly one envelope object on stdout", async () => {
    const specPackRoot = await createSpecPack("cli-io-json");
    const run = await runSourceCli([
      "inspect",
      "--spec-pack-root",
      specPackRoot,
      "--json",
    ]);

    expect(run.exitCode).toBe(0);
    expect(run.stdout.trim().split("\n")).toHaveLength(1);

    const envelope = parseJsonOutput<any>(run.stdout);
    expect(envelope.command).toBe("inspect");
  });

  test("persisted artifact json matches the stdout envelope", async () => {
    const specPackRoot = await createSpecPack("cli-io-artifact");
    const run = await runSourceCli([
      "inspect",
      "--spec-pack-root",
      specPackRoot,
      "--json",
    ]);

    expect(run.exitCode).toBe(0);

    const envelope = parseJsonOutput<any>(run.stdout);
    const artifactPath = envelope.artifacts[0].path as string;
    const persisted = JSON.parse(await Bun.file(artifactPath).text());

    expect(persisted).toEqual(envelope);
  });
});

import { describe, expect, test } from "bun:test";
import { join } from "node:path";

import { ensureTeamImplLog } from "../core/log-template";
import { createTempDir, writeTextFile } from "./test-helpers";

describe("team-impl log template", () => {
  test("TC-1.3a initializes a new log with the required recovery headings", async () => {
    const specPackRoot = await createTempDir("log-init");

    const result = await ensureTeamImplLog({
      specPackRoot,
      storyIds: ["00-foundation", "01-next"],
    });

    expect(result.created).toBe(true);
    expect(result.path).toBe(join(specPackRoot, "team-impl-log.md"));

    const content = await Bun.file(result.path).text();
    expect(content).toContain("# Team Implementation Log");
    expect(content).toContain("## Run Overview");
    expect(content).toContain("- State: SETUP");
    expect(content).toContain("## Run Configuration");
    expect(content).toContain("## Verification Gates");
    expect(content).toContain("## Story Sequence");
    expect(content).toContain("- 00-foundation");
    expect(content).toContain("- 01-next");
    expect(content).toContain("## Story Receipts");
    expect(content).toContain("## Cumulative Baselines");
    expect(content).toContain("## Cleanup / Epic Verification");
    expect(content).toContain("## Open Risks / Accepted Risks");
  });

  test("TC-1.3b preserves an existing log for resume instead of overwriting it", async () => {
    const specPackRoot = await createTempDir("log-resume");
    const existingPath = join(specPackRoot, "team-impl-log.md");
    await writeTextFile(existingPath, "# Existing Log\n\nresume marker\n");

    const result = await ensureTeamImplLog({
      specPackRoot,
      storyIds: ["00-foundation"],
    });

    expect(result.created).toBe(false);
    expect(await Bun.file(existingPath).text()).toBe(
      "# Existing Log\n\nresume marker\n"
    );
  });
});

