            customStoryImplPromptInsert: "absent",
            customStoryVerifierPromptInsert: "absent",
          },
          blockers: ["Missing required artifact: epic.md"],
          notes: [],
        },
        errors: [],
        warnings: [],
        artifacts: [],
        startedAt: "2026-04-20T00:00:00.000Z",
        finishedAt: "2026-04-20T00:00:00.500Z",
